  "name": "appetyt",
  "version": "1.0.0",
  "engines": {
    "node": ">=18.0.0"
  },
  "scripts": {
    "build": "mkdir -p dist && cp index.html robots.txt sitemap.xml 404.html _headers dist/ && cp -r dallas chicago nyc houston austin los-angeles seattle san-antonio dist/",
    "cap:sync": "npm run build && npx cap sync ios",
    "cap:open": "npx cap open ios",
    "cap:build": "npm run build && npx cap sync ios && npx cap open ios"
  },
  "dependencies": {
    "@capacitor/app": "^6.0.0",
    "@capacitor/core": "^6.0.0",
    "@capacitor/haptics": "^6.0.0",
    "@capacitor/ios": "^6.0.0",
    "@capacitor/keyboard": "^6.0.0",
    "@capacitor/push-notifications": "^6.0.0",
    "@capacitor/splash-screen": "^6.0.0",
    "@capacitor/status-bar": "^6.0.0"
  },
  "devDependencies": {
    "@capacitor/cli": "^6.0.0",
    "jsonwebtoken": "^9.0.3",
    "typescript": "^6.0.2"
  }
}

{
  "name": "Appetyt",
  "short_name": "Appetyt",
  "description": "Discover the best restaurants in every city",
  "start_url": "/",
  "display": "standalone",
  "background_color": "#0a0d14",
  "theme_color": "#c9a84c",
  "icons": [
    {
      "src": "/icons/icon-192.png",
      "sizes": "192x192",
      "type": "image/png"
    },
    {
      "src": "/icons/icon-512.png",
      "sizes": "512x512",
      "type": "image/png"
    }
  ],
  "categories": ["food", "travel", "lifestyle"]
}

import type { CapacitorConfig } from '@capacitor/cli';

const config: CapacitorConfig = {
  appId: 'app.appetyt.ios',
  appName: 'Appetyt',
  webDir: 'dist',

  server: {
    iosScheme: 'https',
    allowNavigation: [
      'appetyt.app',
      'cdn.jsdelivr.net',
      '*.supabase.co',
      '*.tile.openstreetmap.org',
      'fonts.googleapis.com',
      'fonts.gstatic.com'
    ]
  },

  plugins: {
    StatusBar: {
      style: 'LIGHT',
      backgroundColor: '#0a0d14',
      overlaysWebView: false
    },
    SplashScreen: {
      launchShowDuration: 2000,
      backgroundColor: '#0a0d14',
      showSpinner: false,
      launchAutoHide: true
    },
    Keyboard: {
      resize: 'body',
      style: 'DARK'
    }
  },

  ios: {
    contentInset: 'automatic',
    backgroundColor: '#0a0d14',
    preferredContentMode: 'mobile',
    scheme: 'Appetyt',
    // Universal Links (for https://appetyt.app links to open the app)
    associatedDomains: ['applinks:appetyt.app']
  }
};

export default config;

